// 1. Get the data from your Webhook
// Note: Based on your screenshots, the data is inside body.record
const inputData = $('Webhook').first().json.body.record; 

// 2. Determine the Name based on Project ID
const rawProjectID = inputData["Project ID"];

// LOGIC CHANGE: 
// Check if "Project ID" is a Linked Record (Array) or just a Text String.
// - If it's an Array (Linked Record), we grab the .name of the first item.
// - If it's a String, we use it directly.
const finalClientName = (Array.isArray(rawProjectID) && rawProjectID[0]) 
    ? rawProjectID[0].name 
    : rawProjectID;

// ---------------------------------------------------------
// 3. The Folder Checking Logic (Remains the same)
// ---------------------------------------------------------

// Get list of existing folders from the previous ClickUp node
const existingFolders = items.map(item => item.json.name);

// Check if our final name exists in that list
const folderExists = existingFolders.includes(finalClientName);

return [
  {
    json: {
      exists: folderExists,
      clientName: finalClientName // Passes the Project ID to the next step
    }
  }
];

const items = $input.all();

const output = [];

items.forEach((item, index) => {
  const originalJson = item.json;

  // Supports both direct Airtable payloads and nested "fields" payloads
  const pdevRequirements =
    originalJson["PDEV Requirements"] ||
    originalJson.fields?.["PDEV Requirements"] ||
    [];

  // If there are no PDEV requirements, keep the item as-is
  if (!Array.isArray(pdevRequirements) || pdevRequirements.length === 0) {
    output.push({
      json: originalJson,
      binary: item.binary,
      pairedItem: { item: index },
    });
    return;
  }

  // Create one output item per PDEV Requirement
  pdevRequirements.forEach((pdevRequirementId) => {
    // n8n-compatible deep copy
    const newJson = JSON.parse(JSON.stringify(originalJson));

    // If payload uses nested fields object
    if (newJson.fields && Array.isArray(newJson.fields["PDEV Requirements"])) {
      newJson.fields["PDEV Requirements"] = [pdevRequirementId];
    }

    // If payload uses direct Airtable fields
    if (Array.isArray(newJson["PDEV Requirements"])) {
      newJson["PDEV Requirements"] = [pdevRequirementId];
    }

    // Helper field for easier mapping in the next node
    newJson.pdevRequirementId = pdevRequirementId;

    output.push({
      json: newJson,
      binary: item.binary,
      pairedItem: { item: index },
    });
  });
});

return output;

